  "eb.requireSEBDesc": { en: "Hard OS-level lockdown. The exam can only be taken inside SEB — the server rejects any other browser.", fr: "Verrouillage strict au niveau du système. L'examen ne peut être passé que dans SEB — le serveur rejette tout autre navigateur.", es: "Bloqueo estricto a nivel de sistema. El examen solo puede realizarse dentro de SEB — el servidor rechaza cualquier otro navegador.", pt: "Bloqueio rígido em nível de sistema. O exame só pode ser feito dentro do SEB — o servidor rejeita qualquer outro navegador.", ar: "قفل صارم على مستوى نظام التشغيل. لا يمكن أداء الامتحان إلا داخل SEB — يرفض الخادم أي متصفح آخر." },
  "eb.sebPlatforms": { en: "Requires Windows, macOS or iPad — not available on Android or Chromebook.", fr: "Nécessite Windows, macOS ou iPad — non disponible sur Android ou Chromebook.", es: "Requiere Windows, macOS o iPad — no disponible en Android o Chromebook.", pt: "Requer Windows, macOS ou iPad — não disponível em Android ou Chromebook.", ar: "يتطلب Windows أو macOS أو iPad — غير متاح على Android أو Chromebook." },
