  "eb.wakeLockResumeFlag": { en: "Flag attempt", fr: "Signaler la tentative", es: "Marcar intento", pt: "Sinalizar tentativa", ar: "الإبلاغ عن المحاولة" },
  "eb.wakeLockResumeHint": { en: "Applies once the candidate's device appears to have been asleep or inactive for 30 seconds or more and has now resumed. \"Pause\" holds the attempt for proctor review, the same as a manual pause.", fr: "S'applique une fois que l'appareil du candidat semble avoir été inactif pendant 30 secondes ou plus puis a repris. « Mettre en pause » retient la tentative pour examen par le surveillant, comme une pause manuelle.", es: "Se aplica una vez que el dispositivo del candidato parece haber estado inactivo 30 segundos o más y se ha reanudado. \"Pausar\" retiene el intento para revisión del supervisor, igual que una pausa manual.", pt: "Aplica-se quando o dispositivo do candidato parece ter ficado inativo por 30 segundos ou mais e foi retomado. \"Pausar\" retém a tentativa para revisão do fiscal, assim como uma pausa manual.", ar: "يُطبَّق عند ظهور أن جهاز المرشح كان خاملاً لمدة 30 ثانية أو أكثر ثم استؤنف. \"إيقاف مؤقت\" يُبقي المحاولة معلّقة لمراجعة المراقب، تمامًا كالإيقاف المؤقت اليدوي." },
  "eb.requireGeofence": { en: "Geofencing", fr: "Géorepérage", es: "Geovallado", pt: "Geofencing", ar: "التسييج الجغرافي" },
