  "eb.egFormula": { en: "e.g. d / t", fr: "p. ex. d / t", es: "p. ej. d / t", pt: "ex.: d / t", ar: "مثال: d / t" },
  "eb.formulaHint": { en: "Use the variable names with + − * / ^ ( ) and functions like sqrt, round, abs, min, max. Computed per candidate.", fr: "Utilisez les noms de variables avec + − * / ^ ( ) et des fonctions comme sqrt, round, abs, min, max. Calculé par candidat.", es: "Usa los nombres de variables con + − * / ^ ( ) y funciones como sqrt, round, abs, min, max. Calculado por candidato.", pt: "Use os nomes das variáveis com + − * / ^ ( ) e funções como sqrt, round, abs, min, max. Calculado por candidato.", ar: "استخدم أسماء المتغيرات مع + − * / ^ ( ) ودوال مثل sqrt وround وabs وmin وmax. تُحسب لكل مرشح." },
  "eb.previewSampleValues": { en: "Preview · sample values", fr: "Aperçu · valeurs d'exemple", es: "Vista previa · valores de ejemplo", pt: "Pré-visualização · valores de exemplo", ar: "معاينة · قيم نموذجية" },
  "eb.addPromptWithMarkers": { en: "Add a prompt with {name} markers…", fr: "Ajoutez un énoncé avec des marqueurs {name}…", es: "Agrega un enunciado con marcadores {name}…", pt: "Adicione um enunciado com marcadores {name}…", ar: "أضف عبارة تحتوي على علامات {name}…" },
  "eb.correctAnswerLabel": { en: "Correct answer:", fr: "Bonne réponse :", es: "Respuesta correcta:", pt: "Resposta correta:", ar: "الإجابة الصحيحة:" },
  "eb.checkFormula": { en: "— (check formula)", fr: "— (vérifier la formule)", es: "— (revisar la fórmula)", pt: "— (verificar a fórmula)", ar: "— (تحقق من الصيغة)" },
  "eb.imageAndRegions": { en: "Image & correct regions", fr: "Image et régions correctes", es: "Imagen y regiones correctas", pt: "Imagem e regiões corretas", ar: "الصورة والمناطق الصحيحة" },
  "eb.changeImage": { en: "Change image", fr: "Changer l'image", es: "Cambiar imagen", pt: "Alterar imagem", ar: "تغيير الصورة" },
  "eb.uploadImage": { en: "Upload image", fr: "Téléverser une image", es: "Subir imagen", pt: "Enviar imagem", ar: "رفع صورة" },
  "eb.imageTooLarge": { en: "Image must be under 2 MB.", fr: "L'image doit faire moins de 2 Mo.", es: "La imagen debe ser menor de 2 MB.", pt: "A imagem deve ter menos de 2 MB.", ar: "يجب أن تكون الصورة أقل من 2 ميغابايت." },
  "eb.hotspotHint": { en: "Click and drag on the image to draw the correct region(s). A click inside any region scores.", fr: "Cliquez et faites glisser sur l'image pour dessiner la ou les régions correctes. Un clic dans une région marque des points.", es: "Haz clic y arrastra sobre la imagen para dibujar la(s) región(es) correcta(s). Un clic dentro de cualquier región puntúa.", pt: "Clique e arraste na imagem para desenhar a(s) região(ões) correta(s). Um clique dentro de qualquer região pontua.", ar: "انقر واسحب على الصورة لرسم المنطقة (المناطق) الصحيحة. يُحتسب النقر داخل أي منطقة." },
  "eb.uploadImageToMark": { en: "Upload an image to mark hotspots.", fr: "Téléversez une image pour marquer des zones sensibles.", es: "Sube una imagen para marcar zonas activas.", pt: "Envie uma imagem para marcar pontos ativos.", ar: "ارفع صورة لتحديد المناطق النشطة." },
