  "eb.multiplyHint": { en: "× every raw score (capped at 100)", fr: "× chaque note brute (plafonné à 100)", es: "× cada puntuación bruta (tope de 100)", pt: "× cada nota bruta (limite de 100)", ar: "× كل درجة خام (بحد أقصى 100)" },
