  "eb.releaseHeldHint": { en: "Students can't see their score until this time.", fr: "Les étudiants ne peuvent pas voir leur note avant cette heure.", es: "Los estudiantes no pueden ver su nota hasta esta hora.", pt: "Os alunos não podem ver sua nota até este horário.", ar: "لا يستطيع الطلاب رؤية درجتهم حتى هذا الوقت." },
  "eb.releaseImmediateHint": { en: "Leave blank to release results as soon as they're graded.", fr: "Laissez vide pour publier les résultats dès qu'ils sont corrigés.", es: "Deja en blanco para publicar los resultados en cuanto se califiquen.", pt: "Deixe em branco para liberar os resultados assim que forem corrigidos.", ar: "اتركه فارغًا لإصدار النتائج بمجرد تصحيحها." },
  "eb.releaseAutoHint": { en: "Left blank — results will be held until the Scheduler window closes ({date}), so early finishers can't share answers with candidates still testing.", fr: "Vide — les résultats seront retenus jusqu'à la fermeture de la fenêtre du planificateur ({date}), pour empêcher les premiers arrivés de partager les réponses avec les candidats qui composent encore.", es: "En blanco — los resultados se retendrán hasta que se cierre la ventana del programador ({date}), para que quienes terminen antes no compartan respuestas con los que aún están rindiendo.", pt: "Em branco — os resultados serão retidos até o fechamento da janela do agendador ({date}), para que quem termine cedo não compartilhe respostas com quem ainda está fazendo a prova.", ar: "فارغ — سيتم الاحتفاظ بالنتائج حتى إغلاق نافذة الجدولة ({date})، حتى لا يشارك من ينهي الاختبار مبكرًا الإجابات مع من لا يزال يخوضه." },
  "eb.anonymousGrading": { en: "Anonymous (double-blind) grading", fr: "Correction anonyme (double aveugle)", es: "Calificación anónima (doble ciego)", pt: "Correção anônima (duplo-cego)", ar: "التصحيح المجهول (مزدوج التعمية)" },
  "eb.anonymousGradingDesc": { en: "Hide candidate identity from graders while marking — names, emails and webcam frames are revealed only after release.", fr: "Masquer l'identité du candidat aux correcteurs pendant la correction — noms, e-mails et images webcam ne sont révélés qu'après la publication.", es: "Ocultar la identidad del candidato a los evaluadores durante la calificación — nombres, correos e imágenes de webcam se revelan solo tras la publicación.", pt: "Ocultar a identidade do candidato dos corretores durante a correção — nomes, e-mails e imagens de webcam só são revelados após a liberação.", ar: "إخفاء هوية المرشح عن المصححين أثناء التصحيح — تُكشف الأسماء والبريد الإلكتروني وصور الكاميرا فقط بعد الإصدار." },
  "eb.applySchemeExisting": { en: "Apply scheme to existing results", fr: "Appliquer le barème aux résultats existants", es: "Aplicar el esquema a los resultados existentes", pt: "Aplicar o esquema aos resultados existentes", ar: "تطبيق النظام على النتائج الحالية" },
