  "acan.errNoRows": { en: "No rows found. Include at least name and email columns (Word files should contain a table with a header row).", fr: "Aucune ligne trouvée. Incluez au moins les colonnes name et email (les fichiers Word doivent contenir un tableau avec une ligne d'en-tête).", es: "No se encontraron filas. Incluye al menos las columnas name y email (los archivos Word deben contener una tabla con fila de encabezado).", pt: "Nenhuma linha encontrada. Inclua ao menos as colunas name e email (arquivos Word devem conter uma tabela com linha de cabeçalho).", ar: "لم يُعثر على صفوف. أدرج عمودي name وemail على الأقل (يجب أن تحتوي ملفات Word على جدول بصف عناوين)." },
  "acan.errReadFile": { en: "Could not read that file. Use a CSV, Excel (.xlsx) or Word (.docx) file.", fr: "Impossible de lire ce fichier. Utilisez un fichier CSV, Excel (.xlsx) ou Word (.docx).", es: "No se pudo leer ese archivo. Usa un archivo CSV, Excel (.xlsx) o Word (.docx).", pt: "Não foi possível ler esse arquivo. Use um arquivo CSV, Excel (.xlsx) ou Word (.docx).", ar: "تعذّرت قراءة الملف. استخدم ملف CSV أو Excel (.xlsx) أو Word (.docx)." },
