  "acan.min6": { en: "min 6 characters", fr: "min 6 caractères", es: "mín. 6 caracteres", pt: "mín. 6 caracteres", ar: "6 أحرف على الأقل" },
  "acan.errNameEmail": { en: "Name and email are required.", fr: "Le nom et l'e-mail sont requis.", es: "El nombre y el correo son obligatorios.", pt: "Nome e e-mail são obrigatórios.", ar: "الاسم والبريد الإلكتروني مطلوبان." },
  "acan.errPw6": { en: "Password must be at least 6 characters.", fr: "Le mot de passe doit comporter au moins 6 caractères.", es: "La contraseña debe tener al menos 6 caracteres.", pt: "A senha deve ter ao menos 6 caracteres.", ar: "يجب أن تتكون كلمة المرور من 6 أحرف على الأقل." },
  "acan.saveChanges": { en: "Save changes", fr: "Enregistrer", es: "Guardar cambios", pt: "Salvar alterações", ar: "حفظ التغييرات" },
