  "acan.enrolIn": { en: "Enrol {name} in an exam (confirmed).", fr: "Inscrire {name} à un examen (confirmé).", es: "Inscribir a {name} en un examen (confirmado).", pt: "Inscrever {name} em um exame (confirmado).", ar: "تسجيل {name} في امتحان (مؤكَّد)." },
  "acan.close": { en: "Close", fr: "Fermer", es: "Cerrar", pt: "Fechar", ar: "إغلاق" },
