  "acan.assignedConfirmed": { en: "{name} assigned & confirmed.", fr: "{name} affecté et confirmé.", es: "{name} asignado y confirmado.", pt: "{name} atribuído e confirmado.", ar: "تم تعيين {name} وتأكيده." },
  "acan.couldNotAssign": { en: "Could not assign.", fr: "Impossible d'affecter.", es: "No se pudo asignar.", pt: "Não foi possível atribuir.", ar: "تعذّر التعيين." },
  "acan.deleteTitle": { en: "Delete student?", fr: "Supprimer l'étudiant ?", es: "¿Eliminar estudiante?", pt: "Excluir estudante?", ar: "حذف الطالب؟" },
  "acan.deleteWarn": { en: "{name} and all their attempts, results and certificates will be permanently removed.", fr: "{name} ainsi que toutes ses tentatives, résultats et certificats seront définitivement supprimés.", es: "{name} y todos sus intentos, resultados y certificados se eliminarán permanentemente.", pt: "{name} e todas as suas tentativas, resultados e certificados serão removidos permanentemente.", ar: "سيُحذف {name} وجميع محاولاته ونتائجه وشهاداته نهائيًا." },
  "acan.resendInvite": { en: "Resend invitation", fr: "Renvoyer l'invitation", es: "Reenviar invitación", pt: "Reenviar convite", ar: "إعادة إرسال الدعوة" },
  "acan.resendInviteTitle": { en: "Resend invitation", fr: "Renvoyer l'invitation", es: "Reenviar invitación", pt: "Reenviar convite", ar: "إعادة إرسال الدعوة" },
  "acan.resendInviteWarn": { en: "This generates a brand-new temporary password for {name} and emails it to {email}, replacing their current password. Use this if their original invitation never arrived.", fr: "Un nouveau mot de passe temporaire sera généré pour {name} et envoyé par e-mail à {email}, remplaçant son mot de passe actuel. Utilisez ceci si son invitation d'origine n'est jamais arrivée.", es: "Esto genera una contraseña temporal nueva para {name} y la envía por correo a {email}, reemplazando su contraseña actual. Úsalo si su invitación original nunca llegó.", pt: "Isso gera uma nova senha temporária para {name} e a envia por e-mail para {email}, substituindo a senha atual. Use isso se o convite original nunca chegou.", ar: "سيؤدي هذا إلى إنشاء كلمة مرور مؤقتة جديدة لـ {name} وإرسالها عبر البريد الإلكتروني إلى {email}، لتحل محل كلمة المرور الحالية. استخدم هذا إذا لم تصل الدعوة الأصلية." },
  "acan.resendInviteSent": { en: "New invitation sent to {email}.", fr: "Nouvelle invitation envoyée à {email}.", es: "Nueva invitación enviada a {email}.", pt: "Novo convite enviado para {email}.", ar: "تم إرسال دعوة جديدة إلى {email}." },
  "acan.resendInviteFailed": { en: "The password was reset, but the email still failed to send — the student can't sign in with it until they actually receive it. Check Communication → Broadcast for the delivery error, fix it, then use Resend invitation again (safe to retry, it just issues another fresh password).", fr: "Le mot de passe a été réinitialisé, mais l'e-mail n'a toujours pas pu être envoyé — l'étudiant ne pourra pas se connecter tant qu'il ne l'aura pas reçu. Consultez Communication → Diffusion pour voir l'erreur d'envoi, corrigez-la, puis utilisez à nouveau Renvoyer l'invitation (sans risque, cela génère simplement un nouveau mot de passe).", es: "La contraseña se restableció, pero el correo aún no se pudo enviar — el estudiante no podrá iniciar sesión hasta recibirlo. Revisa Comunicación → Difusión para ver el error de envío, corrígelo y usa Reenviar invitación de nuevo (seguro de repetir, solo genera otra contraseña nueva).", pt: "A senha foi redefinida, mas o e-mail ainda falhou ao enviar — o aluno não conseguirá entrar até recebê-lo. Veja Comunicação → Transmissão para o erro de envio, corrija-o e use Reenviar convite novamente (seguro repetir, apenas gera outra senha nova).", ar: "تمت إعادة تعيين كلمة المرور، لكن فشل إرسال البريد الإلكتروني مجددًا — لن يتمكن الطالب من تسجيل الدخول حتى يستلمها فعليًا. راجع التواصل ← البث لمعرفة خطأ الإرسال، ثم أصلحه واستخدم إعادة إرسال الدعوة مرة أخرى (آمن للتكرار، فهو يُصدر كلمة مرور جديدة أخرى فقط)." },

