  "acls.importRosterDesc": { en: "Upload a student list to sync this class's roster. Existing students (matched by email) are added; new emails get a new account and an invitation. Re-uploading later also removes any current member no longer in the file.", fr: "Téléversez une liste d'étudiants pour synchroniser la liste de cette classe. Les étudiants existants (associés par e-mail) sont ajoutés ; les nouveaux e-mails obtiennent un compte et une invitation. Un nouveau téléversement supprime aussi les membres actuels absents du fichier.", es: "Sube una lista de estudiantes para sincronizar la lista de esta clase. Los estudiantes existentes (por correo) se añaden; los correos nuevos reciben una cuenta e invitación. Volver a subir el archivo también elimina a los miembros actuales que ya no aparezcan en él.", pt: "Envie uma lista de alunos para sincronizar a lista desta turma. Alunos existentes (por e-mail) são adicionados; e-mails novos recebem uma conta e um convite. Reenviar o arquivo depois também remove quem não estiver mais nele.", ar: "ارفع قائمة طلاب لمزامنة قائمة هذا الصف. يُضاف الطلاب الحاليون (بمطابقة البريد الإلكتروني)؛ يحصل البريد الجديد على حساب ودعوة. إعادة الرفع لاحقًا تزيل أيضًا أي عضو حالي لم يعد موجودًا في الملف." },
  "acls.willRemoveN": { en: "{n} current member(s) not in this file will be removed from the class:", fr: "{n} membre(s) actuel(s) absent(s) de ce fichier seront retirés de la classe :", es: "Se eliminarán de la clase {n} miembro(s) actual(es) que no están en este archivo:", pt: "{n} membro(s) atual(is) que não estão neste arquivo serão removidos da turma:", ar: "سيتم إزالة {n} عضوًا حاليًا غير موجود في هذا الملف من الصف:" },
  "acls.importAndSync": { en: "Import & sync", fr: "Importer et synchroniser", es: "Importar y sincronizar", pt: "Importar e sincronizar", ar: "استيراد ومزامنة" },
  "acls.syncSummary": { en: "{created} new, {existing} existing added, {removed} removed", fr: "{created} nouveaux, {existing} existants ajoutés, {removed} retirés", es: "{created} nuevos, {existing} existentes añadidos, {removed} eliminados", pt: "{created} novos, {existing} existentes adicionados, {removed} removidos", ar: "{created} جديد، {existing} حالي مُضاف، {removed} تمت إزالته" },
